import os
from setuptools import setup, find_packages

def install_dependencies():
    try:
        os.system('pip install -r requirements.txt')
        print("Dependencies installed successfully.")
    except Exception as e:
        print(f"An error occurred while installing dependencies: {str(e)}")

def run_tests():
    try:
        os.system('python -m unittest discover')
        print("Tests passed successfully.")
    except Exception as e:
        print(f"An error occurred while running tests: {str(e)}")

def package_for_deployment():
    try:
        setup(
            packages=find_packages(),
            include_package_data=True
        )
        print("Package prepared for deployment.")
    except Exception as e:
        print(f"An error occurred while preparing package for deployment: {str(e)}")

if __name__ == "__main__":
    install_dependencies()
    run_tests()
    package_for_deployment()